import { Result, err, ok } from 'neverthrow';
import { ScrapeRequest, ScrapeResponse } from '../../../firecrawl-compat/src';
import { CrawlEngine, CrawlFailure } from '../engine';

export class ManualReviewEngine implements CrawlEngine {
  readonly name = 'manual-review';
  readonly priority = 100;

  supports(_input: ScrapeRequest): boolean {
    return true;
  }

  async scrape(input: ScrapeRequest): Promise<Result<ScrapeResponse, CrawlFailure>> {
    // Return a specific failure code that indicates manual review is needed
    return err({
      code: 'LOGIN_REQUIRED', // This code is often used to trigger manual review in CrawlX
      message: 'Manual review required for this page',
      engineName: this.name,
    });
  }
}
